# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import json
import websockets

clients = [] # list of connected clients
items = {}   # dict storing items available in the game
ownerships = {} # dict storing ownerships of items

# Define message handlers
async def handle_message(websocket, path):
    async for message in websocket:
        data = json.loads(message)
        
        if 'command' not in data or 'args' not in data:
            return await websocket.send("Invalid command format")

        command = data['command']
        args = data['args']

        if command == "add_item": # Add item to the game
            name, count = args[0], int(args[1])
            
            if name in items:
                items[name] += count
            else:
                items[name] = count
                
            await websocket.send("Item added")
        
        elif command == "transfer_item": # Transfer item ownership
            giver, receiver, name, count = args[0], args[1], args[2], int(args[3])
            
            if items[name] < count:
                return await websocket.send("Not enough items")
                
            if (giver in ownerships and ownerships[giver].get(name, 0) < count):
                return await websocket.send("Giver doesn't own that many items")
            
            # Deduct from giver's inventory
            if name not in ownerships[giver]:
                ownerships[giver][name] = 0
            ownerships[giver][name] -= count
            
            # Add to receiver's inventory
            if name not in ownerships[receiver]:
                ownerships[receiver][name] = 0
            ownerships[receiver][name] += count
            
            await websocket.send("Item transferred")
        
        else:
            await websocket.send(f"Unknown command {command}")

start_server = websockets.serve(handle_message, 'localhost', 8765)

asyncio.get_event_loop().run_until_complete(start_server)
asyncio.get_event_loop().run_forever()